cd /tmp && python3 2>/tmp/err3.txt <<'EOF'
import mteb, pickle, numpy as np
res = pickle.load(open('/tmp/res.pkl','rb'))
b = mteb.get_benchmark('MTEB(Scandinavian, v1)')
tasknames = set(t.metadata.name for t in b.tasks)
NT = len(tasknames)
rows=[]
for mr in res.model_results:
    scores={}
    for tr in mr.task_results:
        if tr.task_name in tasknames:
            try:
                s = tr.get_score()
            except Exception:
                continue
            scores[tr.task_name]=s
    if len(scores)==NT:
        rows.append((mr.model_name, 100*np.mean(list(scores.values())), len(scores)))
rows.sort(key=lambda x:-x[1])
print("models with all",NT,"tasks:",len(rows))
for r in rows[:20]:
    print(f"{r[1]:.2f}  {r[0]}")
EOF
